form:Form.form:Scripts:
		function Validar(me)
{
		var sum = 0;
		duracion = Ctrl("n_duracion_hs").GetXValue();
		if (duracion != "")
		{
				for (i = 0; i < Ctrl("MAIN_GRID").TotalRowsCount(); i++)
		 		{		 				
		 				f_ini = str2datetime(Ctrl("MAIN_GRID").GetCellXValue("f_fecha_hora_ini", i));
		 				f_fin = str2datetime(Ctrl("MAIN_GRID").GetCellXValue("f_fecha_hora_fin", i));		 				
		 				sum = sum + Math.abs(f_fin - f_ini) / 3600000;

		 		}		 		
		 		if (sum != duracion) 
		 		{	 				
		 				me.SetError('La duración de las clases (' + sum + ' horas) no concuerda con la duración del dictado (' + duracion + ' horas)');
		 				return false;
		 		}
		} 

// Validar Superposicion de clases
		band = false;
 		for (i = 0; i < Ctrl("MAIN_GRID").TotalRowsCount(); i++)
 		{   
 				f_ini1 = Ctrl("MAIN_GRID").GetCellXValue("f_fecha_hora_ini", i);
 				f_fin1 = Ctrl("MAIN_GRID").GetCellXValue("f_fecha_hora_fin", i);
 				for (j = i+1; j < Ctrl("MAIN_GRID").TotalRowsCount(); j++)
		 		{
		 				f_ini2 = Ctrl("MAIN_GRID").GetCellXValue("f_fecha_hora_ini", j);
 						f_fin2 = Ctrl("MAIN_GRID").GetCellXValue("f_fecha_hora_fin", j);

 						if (f_ini1 < f_fin2 && f_fin1 > f_ini2)
 						{
 								me.SetError('Las clases se superponen');
 						 		return false;
 						}
		 		}		 		
 		} 		
 		return true;
}
